use std::sync::{Arc, Mutex};
use std::thread;
fn run(a: Arc<Mutex<i32>>, b: Arc<Mutex<i32>>) {
    let a2 = a.clone(); let b2 = b.clone();
    let t1 = thread::spawn(move || { let _x = a.lock().unwrap(); let _y = b.lock().unwrap(); });
    let t2 = thread::spawn(move || { let _y = b2.lock().unwrap(); let _x = a2.lock().unwrap(); });
    let _ = t1.join(); let _ = t2.join();
}

use std::sync::mpsc::sync_channel;
use std::thread;
pub fn run() {
    let (tx, rx) = sync_channel::<u32>(0);
    let h = thread::spawn(move || { let _ = tx.send(1); let _ = tx.send(2); });
    let _ = rx.recv();
    let _ = h.join();
}

use std::sync::atomic::{AtomicBool, Ordering};
use std::sync::Arc;
use std::thread;
pub fn run(flag: Arc<AtomicBool>, data: Arc<std::sync::atomic::AtomicU64>) {
    let f = flag.clone(); let d = data.clone();
    let _ = thread::spawn(move || { d.store(42, Ordering::Relaxed); f.store(true, Ordering::Relaxed); });
    while !flag.load(Ordering::Relaxed) {}
    let _v = data.load(Ordering::Relaxed);
}

use std::sync::RwLock;
pub fn run(lock: &RwLock<i32>) {
    let r = lock.read().unwrap();
    let _v = *r;
    let mut w = lock.write().unwrap();
    *w += 1;
}

use std::sync::{Arc, Barrier};
use std::thread;
pub fn run() {
    let b = Arc::new(Barrier::new(3));
    let mut hs = vec![];
    for _ in 0..2 {
        let b = b.clone();
        hs.push(thread::spawn(move || { b.wait(); }));
    }
    for h in hs { let _ = h.join(); }
}

